SELECT command_name 
FROM commands 
WHERE command_id = 1;

SELECT COUNT(*) AS total_invalid_commands
FROM inbound_commands ic
JOIN command_responses cr ON ic.command_id = cr.command_id;

SELECT total_commands
FROM command_statistics
WHERE date = '2023-10-02';

SELECT user_id
FROM inbound_commands
WHERE status = 'pending';

SELECT type_name
FROM command_types
WHERE type_id = 2;

SELECT COUNT(*) 
FROM inbound_commands 
WHERE status = 'failed';

SELECT COUNT(*) AS total_processed_commands
FROM inbound_commands
WHERE DATE(timestamp) = '2023-10-01' AND status = 'processed';

SELECT COUNT(*) AS total_processed_commands
FROM inbound_commands
WHERE user_id = 1 AND status = 'processed';

SELECT COUNT(DISTINCT inbound_id) 
FROM inbound_commands 
WHERE status = 'processed';
